#include <iostream>
#include <string>

struct Box {
    std::string value;
    auto& get(this auto& self) { return self.value; }
};

int main() {
    Box b{"hello"};
    const Box cb{"world"};
    b.get() = "hi";
    std::cout << b.get() << "\n";
    std::cout << cb.get() << "\n";
}

#include <iostream>
#include <utility>

struct Buffer {
    int data = 42;
    // C++23: one method handles all value categories
    auto&& get(this auto&& self) {
        return std::forward_like<decltype(self)>(self.data);
    }
};

int main() {
    Buffer b;
    const Buffer cb;
    std::cout << b.get() << "\n";        // lvalue
    std::cout << cb.get() << "\n";       // const lvalue
    std::cout << Buffer{}.get() << "\n"; // rvalue
}

#include <iostream>
#include <string>

struct Config {
    std::string host = "localhost";
    int port = 8080;

    auto& set_host(this auto& self, std::string h) {
        self.host = std::move(h);
        return self;
    }
    auto& set_port(this auto& self, int p) {
        self.port = p;
        return self;
    }
    void print() const {
        std::cout << host << ":" << port << "\n";
    }
};

int main() {
    Config c;
    c.set_host("example.com").set_port(443).print();
}
